        'model_sources.approve_folder',
        'verified',
        checks=[
            {'id':'explicit_confirmation','ok':True,'message':'Operator confirmed the folder approval.'},
            {'id':'specific_folder_only','ok':True,'message':'Whole-drive scanning remained prohibited.'},
            {'id':'model_files_unchanged','ok':True,'message':'No model file was modified.'},
        ],
        details={'path':result.get('path'),'scope':result.get('scope'),'model_count':result.get('model_count',0)},
