def _bibliotheca_json(route,timeout=2.0):
    import urllib.request
    with urllib.request.urlopen(BIBLIOTHECA_URL+route,timeout=timeout) as response:
        return json.loads(response.read().decode('utf-8',errors='replace'))

def _bibliotheca_database_state():
    empty={'documents':0,'pages':0,'searchable':0,'low_text':0,'ocr_copies':0,'shelves':0,'duplicate_groups':0,'text_chars':0,'research_saved':0}
    if not BIBLIOTHECA_DATABASE.is_file():
        return empty,[]
    import sqlite3
    connection=None
    try:
        uri=BIBLIOTHECA_DATABASE.resolve().as_uri()+'?mode=ro'
        connection=sqlite3.connect(uri,uri=True,timeout=4)
        connection.row_factory=sqlite3.Row
        row=connection.execute("""
            SELECT COUNT(*) documents,COALESCE(SUM(page_count),0) pages,
            COALESCE(SUM(text_chars),0) text_chars,
            SUM(CASE WHEN text_status IN ('searchable','searchable_ocr_copy','partially_searchable') THEN 1 ELSE 0 END) searchable,
            SUM(CASE WHEN text_status='image_only_or_low_text' THEN 1 ELSE 0 END) low_text,
            SUM(is_ocr_copy) ocr_copies FROM documents
        """).fetchone()
        shelf_rows=connection.execute("""
            SELECT CASE WHEN INSTR(rel_path,'/')>0 THEN SUBSTR(rel_path,1,INSTR(rel_path,'/')-1) ELSE 'Library' END shelf,
            COUNT(*) documents,COALESCE(SUM(page_count),0) pages
            FROM documents GROUP BY shelf ORDER BY shelf COLLATE NOCASE
        """).fetchall()
        duplicate_groups=connection.execute("""
            SELECT COUNT(*) FROM (
              SELECT sha256 FROM documents WHERE COALESCE(sha256,'')<>'' GROUP BY sha256 HAVING COUNT(*)>1
            )
