            if marker in {0x01,0xD0,0xD1,0xD2,0xD3,0xD4,0xD5,0xD6,0xD7,0xD8,0xD9}:
                continue
            if position+2>len(payload):break
            length=int.from_bytes(payload[position:position+2],'big')
            if length<2 or position+length>len(payload):break
            if marker in sof:
                if length<7:break
                height=int.from_bytes(payload[position+3:position+5],'big')
                width=int.from_bytes(payload[position+5:position+7],'big')
                return 'image/jpeg',width,height
            position+=length
        raise MissionRequestError('JPEG dimensions could not be verified.')
    if len(payload)>=30 and payload[:4]==b'RIFF' and payload[8:12]==b'WEBP':
