_GUARDED_STREAM_BOUNDARY=re.compile(r'[.!?](?:["\')\]]*)?\s+|\n+')

def iter_chat_stream(payload,timeout=300):
    import urllib.request
    request=dict(payload or {})
    request['stream']=True
    req=urllib.request.Request(
        CHAT_API,
        data=json.dumps(request).encode(),
        headers={
            'Content-Type':'application/json',
            'Accept':'text/event-stream',
        },
    )
    with urllib.request.urlopen(req,timeout=timeout) as response:
        for raw_line in response:
            line=raw_line.decode('utf-8',errors='replace').strip()
            if not line or line.startswith(':') or not line.startswith('data:'):
                continue
            data=line[5:].strip()
            if data=='[DONE]':
                return
            event=json.loads(data)
            if isinstance(event,dict) and event.get('error'):
                raise RuntimeError(str(event.get('error')))
            choices=event.get('choices') if isinstance(event,dict) else None
            if not isinstance(choices,list) or not choices:
                continue
            choice=choices[0] if isinstance(choices[0],dict) else {}
            delta=choice.get('delta') if isinstance(choice.get('delta'),dict) else {}
            text=delta.get('content')
            if isinstance(text,str) and text:
                yield text

def guarded_stream_units(buffer,final=False):
    value=buffer or ''
    if final:
        return ([value] if value else []),''
    units=[]; start=0
    for match in _GUARDED_STREAM_BOUNDARY.finditer(value):
        end=match.end()
        unit=value[start:end]
        if unit:
            units.append(unit)
        start=end
    return units,value[start:]

