let extensionInventoryData=null;
let extensionStatePreviewData=null;
function inventorySize(value){
    let n=Number(value);
    if(!Number.isFinite(n)||n<0)return '—';
    if(n<1024)return `${n} B`;
    if(n<1024*1024)return `${(n/1024).toFixed(1)} KB`;
    if(n<1024*1024*1024)return `${(n/1024/1024).toFixed(2)} MB`;
    return `${(n/1024/1024/1024).toFixed(2)} GB`;
}
function inventoryStatusClass(status){
    status=String(status||'').toUpperCase();
    if(status==='VERIFIED')return 'verified';
    if(status==='INSTALLED')return 'installed';
    if(status==='MISSING')return 'missing';
    return 'attention';
}
function inventoryItemById(id){
    return (extensionInventoryData?.items||[]).find(item=>item.id===id)||null;
}
function inventoryItemByStateKey(key){
    key=String(key||'').toLowerCase();
    return (extensionInventoryData?.items||[]).find(item=>String(item.state_control?.key||'').toLowerCase()===key)||null;
}
function extensionStateLabel(control){
    if(!control?.eligible)return 'STATE LOCKED';
    return control.effective_enabled?'ENABLED':'DISABLED';
}
function renderExtensionInventory(){
    let data=extensionInventoryData;
    if(!data||!q('extInventoryList'))return;
    let search=String(q('extInventorySearch')?.value||'').trim().toLowerCase();
    let category=q('extInventoryCategory')?.value||'all';
    let status=q('extInventoryStatus')?.value||'all';
    let requirement=q('extInventoryRequirement')?.value||'all';
    let items=(data.items||[]).filter(item=>{
        if(category!=='all'&&item.category!==category)return false;
        if(status!=='all'&&item.status!==status)return false;
        if(requirement==='required'&&!item.required)return false;
        if(requirement==='optional'&&item.required)return false;
        if(search){
            let hay=[
                item.name,item.path,item.relative_path,item.department,item.source,
                item.category,item.kind,item.health,item.description,item.version,
                item.state_control?.key,item.state_control?.effective_enabled?'enabled':'disabled'
            ].join(' ').toLowerCase();
            if(!hay.includes(search))return false;
        }
        return true;
    });
    q('extInventoryList').innerHTML=items.map(item=>{
        let cls=inventoryStatusClass(item.status);
        let control=item.state_control||null;
        let badges=[
            `<span class="inventorybadge ${cls}">${esc(item.status)}</span>`,
            `<span class=inventorybadge>${esc(item.category)}</span>`,
            `<span class=inventorybadge>${item.required?'REQUIRED':'OPTIONAL'}</span>`,
            item.department?`<span class=inventorybadge>${esc(item.department)}</span>`:'',
            control?`<span class=inventorybadge>${esc(extensionStateLabel(control))}</span>`:'',
            control?.override_present?'<span class="inventorybadge attention">OVERRIDE</span>':'',
        ].join('');
        let details=[
            `Version: ${item.version||'Unspecified'}`,
            `Path: ${item.path||'(no path registered)'}`,
            `Size: ${inventorySize(item.size_bytes)}`,
            `Source: ${item.source||'Unknown'}`,
            item.manifest_path?`Manifest: ${item.manifest_path}`:'',
            item.verification_basis?`Verification: ${item.verification_basis}`:'',
            item.lifecycle?`Lifecycle: ${item.lifecycle}`:'',
            item.security_role?`Security role: ${item.security_role}`:'',
            item.modified?`Modified: ${item.modified}`:'',
        ].filter(Boolean).join('\n');
        let stateDetails='';
        if(control){
            stateDetails=`<div class=inventorystate><b>State:</b> ${control.effective_enabled?'Enabled':'Disabled'} • Manifest default: ${control.manifest_default?'Enabled':'Disabled'} • Override: ${control.override_present?(control.override_enabled?'Enabled':'Disabled'):'None'}${control.dependencies?.length?`<br><b>Depends on:</b> ${esc(control.dependencies.join(', '))}`:''}${control.dependents?.length?`<br><b>Dependents:</b> ${esc(control.dependents.join(', '))}`:''}${!control.eligible?`<br><b>Control locked:</b> ${esc(control.lock_reason||'Not an optional extension.')}`:''}</div>`;
        }
        let actions=[];
        if(item.actions?.open_folder)actions.push(`<button onclick="openExtensionInventoryFolder('${js(item.id)}')">Open Folder</button>`);
        if(item.actions?.open_url)actions.push(`<button onclick="openExtensionInventoryUrl('${js(item.id)}')">Open UI</button>`);
        if(item.actions?.launch)actions.push(`<button onclick="launchExtensionInventoryItem('${js(item.id)}')">${esc(item.actions.launch_label||'Launch')}</button>`);
        if(control?.eligible){
            let action=control.effective_enabled?'disable':'enable';
            actions.push(`<button onclick="previewExtensionState('${js(item.id)}','${action}')">Preview ${action==='enable'?'Enable':'Disable'}</button>`);
            if(control.override_present)actions.push(`<button onclick="previewExtensionState('${js(item.id)}','restore')">Restore Default</button>`);
        }
        if(item.status==='NEEDS_ATTENTION'||item.status==='MISSING'||control)actions.push(`<button onclick="explainExtensionInventoryItem('${js(item.id)}')">Why?</button>`);
        actions.push(`<button onclick="sendInventoryItemToMission('${js(item.id)}')">Send to Mission</button>`);
        return `<div class="inventorycard ${cls}"><h4>${esc(item.name)}</h4><div class=inventorybadges>${badges}</div><div class=inventorymeta>${esc(details)}</div>${item.description?`<div class=inventoryhealth>${esc(item.description)}</div>`:''}<div class=inventoryhealth><b>Health:</b> ${esc(item.health||'No health detail.')}</div>${stateDetails}<div class=inventoryactions>${actions.join('')}</div></div>`;
    }).join('')||'<div class=inventoryempty>No components match the current filters.</div>';
}
