    if(!data?.can_apply){toast('No approved state preview is active.');return;}
    let approval=String(q('extStateApproval')?.value||'').trim();
    if(button)button.disabled=true;
    try{
        let response=await fetch('/api/extensions/state/apply',{
            method:'POST',headers:{'Content-Type':'application/json'},
            body:JSON.stringify({
                target:data.target,
                action:data.action,
                proposal_time:data.proposal_time,
                preview_digest:data.preview_digest,
                approval_phrase:approval
            })
        });
        let result=await response.json();
        if(!response.ok||!result?.ok)throw new Error(result?.message||`HTTP ${response.status}`);
        extensionStatePreviewData=null;
        q('extStatePreview').innerHTML=`<div class="statepreview safe"><h4>VERIFIED STATE CHANGE</h4><div class=whybox>${esc(result.message||'State change applied.')}\nReceipt: ${esc(result.receipt_path||'')}\nBackup: ${esc(result.backup_path||'')}\nState file: ${esc(result.state_file||'')}</div></div>`;
