    </div>
    <div class=actionPath>Project root: ${esc(s.project_root||'')}</div>
    <div class=actionPath>Manifest target: ${esc(s.manifest_target||'')}</div>
    ${d.exported?`<div class=actionPath>Export: ${esc(d.exported.markdown||'')}</div>`:''}`;
