def fox_sentry_incidents(kind='all', limit=100):
    log_path=ROOT/'Logs'/'Security'/'engineering_airlock_events.jsonl'
    verification=verify_airlock_audit_log(log_path)
    chain_alert=airlock_chain_alert(verification)
    requested=str(kind or 'all').strip().lower()
    allowed_filters={'all','test','operational','info','notice','warning','critical'}
    if requested not in allowed_filters:
        requested='all'
    try:
        bounded_limit=max(1,min(int(limit),500))
    except Exception:
        bounded_limit=100

    events=[]
    redactions=0
    read_error=''
    if log_path.exists():
        try:
            lines=log_path.read_text(encoding='utf-8',errors='strict').splitlines()
        except Exception as exc:
            lines=[]
            read_error=f'{type(exc).__name__}: {exc}'
        for line_number,line in enumerate(lines,start=1):
            if not line.strip():
                continue
            try:
                event=json.loads(line)
            except Exception:
                continue
            clean_event,count=redact_mapping(event)
            clean_event['_line_number']=line_number
            redactions+=count
            events.append(clean_event)

    if requested=='test':
        events=[event for event in events if bool(event.get('test_event'))]
    elif requested=='operational':
        events=[event for event in events if not bool(event.get('test_event'))]
    elif requested in {'info','notice','warning','critical'}:
        events=[
            event for event in events
            if not bool(event.get('test_event'))
            and str(event.get('severity') or '').strip().lower()==requested
        ]

    events=list(reversed(events))[:bounded_limit]
    return {
        'ok':bool(verification.get('valid')) and not read_error,
        'read_only':True,
        'chain_valid':bool(verification.get('valid')),
        'verification':verification,
        'chain_alert':chain_alert,
        'events':events,
        'visible_count':len(events),
        'filter':requested,
        'log_exists':log_path.exists(),
        'log_path':str(log_path),
        'read_error':read_error,
        'redactions':redactions,
    }



def trip_sentry_test(d=None):
    request=d or {}
    confirmation=str(request.get('confirmation') or '').strip().upper()
    approval_source=str(request.get('approval_source') or '').strip().lower()
    if confirmation!='TRIP SENTRY TEST' or approval_source!='ui_operator':
        return {
            'ok':False,
            'message':'Trip Sentry denied: explicit operator TEST confirmation was not supplied.',
            'verified':False,
        }

    ensure_web_mission_session()
    mission_id=web_mission_session.session_id or f"web_trip_sentry_{datetime.now():%Y%m%dT%H%M%S}"
    correlation_id=new_airlock_correlation_id()
    receipt=record_trip_sentry_test_event(
        correlation_id=correlation_id,
        mission_id=mission_id,
    )
    verified=bool(receipt.get('verified'))
    return {
        'ok':verified,
        'verified':verified,
        'message':(
            'VERIFIED TEST INCIDENT: Fox Sentry recorded a harmless denial event.'
            if verified
            else 'Trip Sentry failed closed: no verified security receipt was produced.'
        ),
        'receipt':receipt,
        'correlation_id':correlation_id,
        'mission_id':mission_id,
        'test_event':True,
        'operational_change':False,
    }


class Handler(BaseHTTPRequestHandler):
    def body(self):
        n=int(self.headers.get('Content-Length','0') or 0)
        if n<0 or n>MISSION_JSON_MAX_BYTES:
            raise MissionRequestError('JSON request exceeds the 9 MB limit.',413)
        if not n:
            return {}
        try:
            return json.loads(self.rfile.read(n).decode('utf-8',errors='strict'))
        except (UnicodeDecodeError,json.JSONDecodeError) as exc:
            raise MissionRequestError(f'Invalid JSON request: {exc}') from exc
    def sendit(self,b,ct='text/html; charset=utf-8'):
        self.send_response(200); self.send_header('Content-Type',ct); self.send_header('Cache-Control','no-store'); self.end_headers(); self.wfile.write(b)
