            try:
                model_started=time.perf_counter()
                r=post(CHAT_API,{'model':'local-model','messages':request_messages,'temperature':0.7,'max_tokens':768,'stream':False})
                model_ms=round((time.perf_counter()-model_started)*1000,1)

                guard_started=time.perf_counter()
                raw_ans=r['choices'][0]['message']['content'].strip()
                claim_guard=guard_model_action_claims(raw_ans)
