                guard_ms=round((time.perf_counter()-guard_started)*1000,1)

                messages[:]=compact_prior_images(messages)
                messages.append(user_message)
                messages.append({'role':'assistant','content':ans})
                speaker=active_prof()[0].upper()
                web_mission_session.add(speaker,ans)

                archive_started=time.perf_counter()
                archive_receipt=web_mission_session.save()
                archive_ms=round((time.perf_counter()-archive_started)*1000,1)

                state_started=time.perf_counter()
                save_state('Agent response received')
                state_save_ms=round((time.perf_counter()-state_started)*1000,1)

                receipt_started=time.perf_counter()
                completion_receipt=make_tool_receipt(
                    'chat_completion',
                    'verified',
                    checks=[
                        {'id':'chat_api_response','ok':True,'message':'Local chat API returned a response.'},
                        {'id':'image_attachment_verified','ok':True,'message':'Image bytes and metadata were verified before model submission.' if effective_image else 'No image context was supplied.'},
                        {'id':'image_data_not_archived','ok':True,'message':'Mission Archive stores image metadata and SHA-256, never the base64 image payload.'},
                    ],
                    details={'external_action_verified':False,'claim_flagged':claim_guard['flagged'],'profile_id':chat_profile_id,'image':mission_image_receipt_details(effective_image),'image_source':context['source']},
                    actor='mission_console',
                )
                receipt_ms=round((time.perf_counter()-receipt_started)*1000,1)

                timing={
