                    'model_ms':model_ms,
                    'guard_ms':guard_ms,
                    'archive_ms':archive_ms,
                    'state_save_ms':state_save_ms,
                    'receipt_ms':receipt_ms,
                    'server_total_ms':round((time.perf_counter()-request_started)*1000,1),
                }
                archived=bool(archive_receipt.get('verified'))
                self.js({'ok':archived,'answer':ans,'speaker':speaker,'message':'Agent response returned but archive verification failed.' if not archived else 'Agent response archived.','route':'agent_fox','claim_guard':claim_guard,'route_receipt':route_receipt,'completion_receipt':completion_receipt,'archive_receipt':archive_receipt,'session_receipt':session_receipt,'timing':timing,'active_image':context['active_image']})
                return
            except Exception as e:
                answer=f'Chat request failed: {e}'
                web_mission_session.add('SYSTEM',answer)
                archive_started=time.perf_counter()
                archive_receipt=web_mission_session.save()
                archive_ms=round((time.perf_counter()-archive_started)*1000,1)
                timing={
                    'health_ms':health_ms,
                    'model_ms':round((time.perf_counter()-model_started)*1000,1) if 'model_started' in locals() else 0.0,
                    'guard_ms':0.0,
                    'archive_ms':archive_ms,
                    'state_save_ms':0.0,
                    'receipt_ms':0.0,
                    'server_total_ms':round((time.perf_counter()-request_started)*1000,1),
                }
                self.js({'ok':False,'answer':answer,'speaker':'SYSTEM','message':answer,'route':'agent_fox','route_receipt':route_receipt,'archive_receipt':archive_receipt,'session_receipt':session_receipt,'timing':timing})
                return
        self.send_response(404); self.end_headers()
