def _inventory_read_json(path,default):
    path=Path(path)
    if not path.is_file():
        return default,f'Missing file: {path}'
    try:
        data=json.loads(path.read_text(encoding='utf-8'))
    except Exception as exc:
        return default,f'{type(exc).__name__}: {exc}'
    return data,None

def _inventory_resolve_path(value):
    if value is None or str(value).strip()=='':
        return None
    text=os.path.expandvars(str(value).strip())
    path=Path(text)
    if not path.is_absolute():
        path=ROOT/path
    try:
        return path.resolve()
    except Exception:
        return path

def _inventory_relative(path):
    if path is None:
        return ''
    try:
        return str(Path(path).resolve().relative_to(ROOT.resolve())).replace('\\','/')
    except Exception:
        return str(path)

def _inventory_file_details(path):
    path=Path(path) if path is not None else None
    if path is None:
        return {'exists':False,'is_file':False,'is_dir':False,'size_bytes':None,'modified':None}
    try:
        exists=path.exists()
        is_file=path.is_file()
        is_dir=path.is_dir()
        stat=path.stat() if exists else None
        return {
            'exists':exists,
            'is_file':is_file,
            'is_dir':is_dir,
            'size_bytes':stat.st_size if is_file and stat else None,
            'modified':datetime.fromtimestamp(stat.st_mtime).isoformat(timespec='seconds') if stat else None,
        }
    except Exception as exc:
        return {'exists':False,'is_file':False,'is_dir':False,'size_bytes':None,'modified':None,'error':f'{type(exc).__name__}: {exc}'}

def _inventory_manifest_candidates():
    files=[]
    ignored={'__pycache__','.git','node_modules','backups','backup'}
    for base in (ROOT/'Departments',ROOT/'Extensions',ROOT/'Modules'):
        if not base.exists():
            continue
        try:
            for path in base.rglob('*'):
                if not path.is_file() or path.name.lower() not in {'manifest.json','module.json','extension.json'}:
                    continue
                lowered={part.lower() for part in path.parts}
                if lowered & ignored:
                    continue
                files.append(path)
        except Exception:
            continue
    seen=set()
    result=[]
    for path in sorted(files,key=lambda p:str(p).casefold()):
        try:
            key=str(path.resolve()).casefold()
        except Exception:
            key=str(path).casefold()
        if key not in seen:
            seen.add(key)
            result.append(path)
    return result

def _inventory_manifest_records():
    records=[]
    for path in _inventory_manifest_candidates():
        raw,error=_inventory_read_json(path,{})
        if not isinstance(raw,dict):
            raw={}
            error=error or 'Manifest root is not an object.'
        key=str(raw.get('id') or raw.get('key') or raw.get('name') or extension_key_from_path(path)).strip()
        name=str(raw.get('name') or raw.get('title') or path.parent.name).strip()
        version=str(raw.get('version') or '').strip()
        kind=str(raw.get('type') or raw.get('kind') or ('department' if 'departments' in {part.lower() for part in path.parts} else 'extension')).strip().lower()
        required_fields=['name','version']
        missing=[field for field in required_fields if not str(raw.get(field) or '').strip()]
        missing_tools=[]
        for tool in raw.get('tools') or []:
            if not isinstance(tool,dict):
                continue
            import_name=str(tool.get('import') or '').strip()
            if import_name:
                try:
                    if importlib.util.find_spec(import_name) is None:
                        missing_tools.append(import_name)
                except Exception:
                    missing_tools.append(import_name)
        enabled=bool(raw.get('enabled',True))
        required=bool(kind=='department' and enabled)
        records.append({
            'key':key,
            'name':name,
            'version':version or 'Unspecified',
            'kind':kind,
            'required':required,
            'enabled_default':enabled,
            'description':str(raw.get('description') or raw.get('summary') or '').strip(),
            'department':str(raw.get('department') or '').strip(),
            'manifest_path':path,
            'folder_path':path.parent,
            'raw':raw,
            'error':error,
            'missing_fields':missing,
            'missing_tools':sorted(set(missing_tools)),
        })
    return records

def _inventory_status(*,exists,required=False,manifest_ok=True,live=None,verified_contract=False,mismatch=False):
    if mismatch or not manifest_ok:
        return 'NEEDS_ATTENTION'
    if not exists:
        return 'NEEDS_ATTENTION' if required else 'MISSING'
    if live is True or verified_contract:
        return 'VERIFIED'
    return 'INSTALLED'

def _inventory_item(item_id,name,category,source,path=None,version='Unspecified',required=False,status='INSTALLED',health='',description='',department='',kind='',manifest_path=None,verification_basis='',actions=None,extra=None):
    details=_inventory_file_details(path)
    item={
        'id':str(item_id),
