        'is_file':bool(details.get('is_file')),
        'is_dir':bool(details.get('is_dir')),
        'size_bytes':details.get('size_bytes'),
        'modified':details.get('modified'),
        'manifest_path':str(manifest_path) if manifest_path else '',
        'verification_basis':str(verification_basis or ''),
        'actions':dict(actions or {}),
    }
    if details.get('error'):
        item['path_error']=details['error']
    if isinstance(extra,dict):
        item.update(extra)
    return item

def _inventory_application_items(registry):
    items=[]
    applications=registry.get('applications') if isinstance(registry,dict) else []
    for app in applications or []:
        if not isinstance(app,dict):
            continue
        app_id=str(app.get('id') or slug(app.get('name') or 'application')).strip()
        path=_inventory_resolve_path(app.get('path'))
        details=_inventory_file_details(path)
        lifecycle=str(app.get('lifecycle') or 'unknown').strip().lower()
        required=lifecycle=='active'
        mode=str(app.get('health_mode') or 'path').strip().lower()
        url=str(app.get('url') or '').strip()
        live=None
        if mode=='http' and url.lower().startswith(('http://127.0.0.1','http://localhost')):
            live=check(url)
        exists=bool(details.get('exists'))
        verified_contract=bool(exists and mode in {'path','component'})
        status=_inventory_status(
            exists=exists,
            required=required,
            live=live,
            verified_contract=verified_contract,
        )
        if live is True:
            health='Local health endpoint responded.'
            basis='localhost health endpoint + registered path'
        elif exists and mode=='http':
            health='Installed; local service is not currently responding.'
            basis='registered path exists'
        elif exists:
            health='Registered path exists.'
            basis='application registry + path existence'
        elif required:
            health='Active application path is missing.'
            basis='application registry required path'
        else:
            health=f'{lifecycle.title()} application is not installed yet.'
            basis='application registry lifecycle'
        actions={'open_folder':exists}
        if app_id=='comfyui' and exists:
            actions['launch']=True
            actions['launch_label']='Start ComfyUI'
        if url.lower().startswith(('http://127.0.0.1','http://localhost')):
            actions['open_url']=True
        items.append(_inventory_item(
            f'app:{app_id}',
            app.get('name') or app_id,
            'Application / Runtime',
            'Application Registry',
            path=path,
            version=app.get('version') or 'Registry entry',
            required=required,
            status=status,
            health=health,
            description=app.get('notes') or '',
            department=app.get('department') or '',
            kind=app.get('kind') or '',
            verification_basis=basis,
            actions=actions,
            extra={
                'lifecycle':lifecycle,
                'health_mode':mode,
                'url':url,
                'security_role':str(app.get('security_role') or ''),
                'live':live,
            },
        ))
    return items

def _inventory_fleet_items(registry,manifest_by_key,manifest_by_path=None):
    items=[]
    consumed=set()
    shuttles=registry.get('shuttles') if isinstance(registry,dict) else {}
    for key,entry in sorted((shuttles or {}).items(),key=lambda pair:str(pair[0]).casefold()):
        if not isinstance(entry,dict):
            continue
        key=str(entry.get('key') or key)
        path=_inventory_resolve_path(entry.get('path'))
        manifest_path=_inventory_resolve_path(entry.get('manifest_path'))
        manifest=manifest_by_key.get(key.casefold())
        if manifest is None and manifest_path is not None and isinstance(manifest_by_path,dict):
            try:
                manifest=manifest_by_path.get(str(manifest_path.resolve()).casefold())
            except Exception:
                manifest=manifest_by_path.get(str(manifest_path).casefold())
        if manifest:
            consumed.add(str(manifest['manifest_path']).casefold())
        details=_inventory_file_details(path)
        manifest_exists=bool(manifest_path and manifest_path.is_file())
        installed_flag=bool(entry.get('installed'))
        mismatch=bool(installed_flag != bool(details.get('exists')))
        manifest_ok=bool(manifest_exists and not (manifest or {}).get('missing_fields') and not (manifest or {}).get('error'))
        status=_inventory_status(
            exists=bool(details.get('exists')),
            required=False,
            manifest_ok=manifest_ok,
            verified_contract=bool(installed_flag and details.get('exists') and manifest_ok),
            mismatch=mismatch,
        )
        if mismatch:
            health='Fleet registry installation flag does not match the executable path.'
        elif status=='VERIFIED':
            health=str(entry.get('health_message') or 'Executable and manifest are present.')
        elif status=='MISSING':
            health='Optional fleet tool is not installed.'
        else:
            health='Executable is present; manifest verification is incomplete.'
        actions={'open_folder':bool(details.get('exists'))}
        item_id=f'fleet:{key}'
        if item_id in EXTENSION_INVENTORY_SAFE_FLEET_LAUNCH and details.get('exists'):
            actions['launch']=True
            actions['launch_label']='Launch'
        items.append(_inventory_item(
            item_id,
            entry.get('name') or key,
            'Optional Tool',
            'Fleet Registry',
            path=path,
            version=(manifest or {}).get('version') or 'Auto-detected',
            required=False,
            status=status,
            health=health,
            description=(manifest or {}).get('description') or '',
            department=entry.get('department') or '',
            kind=entry.get('kind') or 'application',
            manifest_path=manifest_path,
            verification_basis='fleet registry + executable path + manifest' if status=='VERIFIED' else 'fleet registry and passive path check',
            actions=actions,
            extra={
                'callsign':str(entry.get('callsign') or ''),
                'capabilities':list(entry.get('capabilities') or []),
                'installed_flag':installed_flag,
                'service_state':str(entry.get('service_state') or ''),
                'manifest_valid':manifest_ok,
                'registry_health_status':str(entry.get('health_status') or ''),
            },
        ))
    return items,consumed

def _inventory_manifest_items(records,consumed):
    items=[]
    for record in records:
        if str(record['manifest_path']).casefold() in consumed:
            continue
        manifest_ok=not record['error'] and not record['missing_fields']
        tools_ok=not record['missing_tools']
        status=_inventory_status(
            exists=record['manifest_path'].is_file(),
            required=record['required'],
            manifest_ok=manifest_ok and tools_ok,
            verified_contract=manifest_ok and tools_ok,
        )
        issues=[]
        if record['error']:
            issues.append(record['error'])
        if record['missing_fields']:
            issues.append('Missing fields: '+', '.join(record['missing_fields']))
        if record['missing_tools']:
            issues.append('Missing declared tools: '+', '.join(record['missing_tools']))
        health='Manifest and declared Python tools verified.' if status=='VERIFIED' else ('; '.join(issues) if issues else 'Manifest is present.')
        item_id='manifest:'+slug(record['key']).lower()+':'+hashlib.sha256(str(record['manifest_path']).encode()).hexdigest()[:8]
        items.append(_inventory_item(
            item_id,
            record['name'],
            'Department Manifest' if record['kind']=='department' else 'Extension Manifest',
            'Manifest Discovery',
            path=record['folder_path'],
            version=record['version'],
            required=record['required'],
            status=status,
            health=health,
            description=record['description'],
            department=record['department'],
            kind=record['kind'],
            manifest_path=record['manifest_path'],
            verification_basis='manifest schema + declared Python tool availability',
            actions={'open_folder':record['folder_path'].exists()},
            extra={
                'missing_fields':record['missing_fields'],
                'missing_tools':record['missing_tools'],
                'enabled_default':record['enabled_default'],
                'depends_on':list(record['raw'].get('depends_on') or []),
                'capabilities':list(record['raw'].get('capabilities') or record['raw'].get('provides') or []),
            },
        ))
    return items

def _inventory_core_items():
    items=[]
    for item_id,name,category,relative in EXTENSION_INVENTORY_CORE_FILES:
        path=ROOT/relative
        exists=path.is_file()
        status='VERIFIED' if exists else 'MISSING'
        health='Core registry module is present.' if exists else 'Optional registry runtime is not present in this build.'
        items.append(_inventory_item(
            item_id,name,category,'Core Runtime',
            path=path,
            version='Python module',
            required=False,
            status=status,
            health=health,
            kind='python_module',
            verification_basis='exact path existence',
            actions={'open_folder':exists},
        ))
    return items

def _inventory_model_items():
    items=[]
    seen=set()
    scanned=0
    truncated=False
    projector_count=0
    configured={
        str(spec.get('model_filename') or '').casefold()
        for spec in (globals().get('WEB_MODEL_PROFILE_RUNTIME') or {}).values()
        if isinstance(spec,dict) and spec.get('model_filename')
    }
    roots=[
        ('Chat Model',ROOT/'Models'/'Chat'),
        ('Chat Model',ROOT/'Models'),
        ('Creative Checkpoint',ROOT/'ComfyUI'/'models'/'checkpoints'),
        ('Creative LoRA',ROOT/'ComfyUI'/'models'/'loras'),
        ('Creative VAE',ROOT/'ComfyUI'/'models'/'vae'),
    ]
    for category,base in roots:
        if not base.exists():
            continue
        try:
            paths=base.rglob('*')
        except Exception:
            continue
        for path in paths:
            if scanned>=EXTENSION_INVENTORY_MAX_MODEL_FILES:
                truncated=True
                break
            if not path.is_file() or path.suffix.lower() not in EXTENSION_INVENTORY_MODEL_SUFFIXES:
                continue
            try:
                resolved=str(path.resolve()).casefold()
            except Exception:
                resolved=str(path).casefold()
            if resolved in seen:
                continue
            seen.add(resolved)
            scanned+=1
            is_projector='mmproj' in path.name.casefold() or 'projector' in path.name.casefold()
            item_category='Vision Projector' if is_projector else category
            if is_projector:
                projector_count+=1
            required=path.name.casefold() in configured or path.name==VISION_PROJECTOR_FILENAME
            expected=EXTENSION_INVENTORY_EXPECTED_SIZES.get(path.name)
            size=path.stat().st_size
            size_verified=expected is not None and size==expected
            mismatch=expected is not None and size!=expected
            status='NEEDS_ATTENTION' if mismatch else ('VERIFIED' if size_verified else 'INSTALLED')
            health=(
                f'Expected size verified: {expected} bytes.'
                if size_verified
                else (
                    f'Expected {expected} bytes but found {size}.'
                    if mismatch
                    else 'Model file is installed; passive inventory did not hash this large file.'
                )
            )
            basis='expected byte-size contract' if expected is not None else 'file existence and metadata only'
            items.append(_inventory_item(
                'model:'+_inventory_relative(path).casefold(),
                path.name,
                item_category,
                'Model Filesystem',
                path=path,
                version=path.suffix.lstrip('.').upper(),
                required=required,
                status=status,
                health=health,
                kind='vision_projector' if is_projector else 'model',
                verification_basis=basis,
                actions={'open_folder':True},
                extra={
                    'expected_size_bytes':expected,
                    'configured_profile_model':path.name.casefold() in configured,
                    'excluded_from_language_model_selector':is_projector,
                },
            ))
        if truncated:
            break
    return items,{
        'files_scanned':scanned,
        'truncated':truncated,
        'projectors_classified_separately':projector_count,
        'projectors_filtered_from_language_models':True,
    }

def extension_inventory_snapshot():
    application_path=ROOT/'Config'/'application_registry.json'
    fleet_path=ROOT/'Config'/'fleet_registry.json'
    state_path=ROOT/'Config'/'extension_state.json'
    application,error_app=_inventory_read_json(application_path,{})
    fleet,error_fleet=_inventory_read_json(fleet_path,{})
    manifests=_inventory_manifest_records()
    manifest_by_key={
        str(record['key']).casefold():record
        for record in manifests
        if record.get('key')
    }
    manifest_by_path={
        str(record['manifest_path'].resolve()).casefold():record
        for record in manifests
    }

    items=[]
    items.extend(_inventory_application_items(application))
    fleet_items,consumed=_inventory_fleet_items(fleet,manifest_by_key,manifest_by_path)
    items.extend(fleet_items)
    items.extend(_inventory_manifest_items(manifests,consumed))
    items.extend(_inventory_core_items())
    model_items,model_scan=_inventory_model_items()
    items.extend(model_items)

    status_order={'NEEDS_ATTENTION':0,'MISSING':1,'INSTALLED':2,'VERIFIED':3}
    items.sort(key=lambda item:(status_order.get(item.get('status'),9),str(item.get('category')).casefold(),str(item.get('name')).casefold()))

    counts={name:sum(1 for item in items if item.get('status')==name) for name in ('VERIFIED','INSTALLED','MISSING','NEEDS_ATTENTION')}
    categories={}
    for item in items:
        categories[item['category']]=categories.get(item['category'],0)+1
    required_items=[item for item in items if item.get('required')]
    required_problems=[
        item for item in required_items
        if item.get('status') in {'MISSING','NEEDS_ATTENTION'}
    ]
    sources={
        'application_registry':{
            'path':str(application_path),
            'exists':application_path.is_file(),
            'error':error_app,
            'records':len(application.get('applications') or []) if isinstance(application,dict) else 0,
        },
        'fleet_registry':{
            'path':str(fleet_path),
            'exists':fleet_path.is_file(),
            'error':error_fleet,
            'records':len(fleet.get('shuttles') or {}) if isinstance(fleet,dict) else 0,
            'mode':str(fleet.get('mode') or '') if isinstance(fleet,dict) else '',
        },
        'manifest_discovery':{
            'roots':[str(ROOT/'Departments'),str(ROOT/'Extensions'),str(ROOT/'Modules')],
            'records':len(manifests),
            'recursive':True,
        },
        'extension_state':{
            'path':str(state_path),
            'exists':state_path.is_file(),
            'mode':'explicit overrides' if state_path.is_file() else 'manifest defaults; no state file created',
        },
    }
    return {
        'ok':True,
        'created':now(),
        'read_only':True,
        'report_only':True,
        'configuration_modified':False,
        'state_file_created':False,
        'summary':{
            'total':len(items),
            'verified':counts['VERIFIED'],
            'installed':counts['INSTALLED'],
            'missing':counts['MISSING'],
            'needs_attention':counts['NEEDS_ATTENTION'],
            'required':len(required_items),
            'optional':len(items)-len(required_items),
            'required_problems':len(required_problems),
            'categories':categories,
            'model_scan':model_scan,
        },
        'sources':sources,
        'items':items,
        'safety':{
            'install':False,
            'remove':False,
            'update':False,
            'configuration_write':False,
            'folder_open':'operator initiated; backend path allowlist',
            'launch':'operator initiated; backend item allowlist only',
        },
        'message':f"Read-only inventory: {len(items)} component(s), {counts['NEEDS_ATTENTION']} needing attention.",
    }

def _inventory_lookup(item_id):
    item_id=str(item_id or '').strip()
    if not item_id:
        return None
    data=extension_inventory_snapshot()
    return next((item for item in data.get('items',[]) if item.get('id')==item_id),None)

def _inventory_allowed_path(path):
    path=_inventory_resolve_path(path)
    if path is None:
        return False
    try:
        resolved=path.resolve()
    except Exception:
        return False
    allowed=[ROOT.resolve()]
    hanger=DRIVE/'Hanger Bay'
    if hanger.exists():
        allowed.append(hanger.resolve())
    for base in allowed:
        try:
            resolved.relative_to(base)
            return True
        except Exception:
            continue
    return False

def open_extension_inventory_folder(d):
    item=_inventory_lookup(d.get('id') if isinstance(d,dict) else '')
    if not item:
        return {'ok':False,'message':'Inventory item not found. No folder was opened.'}
    path=_inventory_resolve_path(item.get('path') or item.get('manifest_path'))
    if path is None or not path.exists():
        return {'ok':False,'message':'Inventory path is missing. No folder was opened.'}
    folder=path if path.is_dir() else path.parent
    if not _inventory_allowed_path(folder):
        return {'ok':False,'message':'Inventory folder is outside the approved FOXAI / Hanger Bay roots.'}
    os.startfile(str(folder))
    receipt=make_tool_receipt(
        'shell.open_extension_inventory_folder',
        'requested',
        details={'item_id':item['id'],'path':str(folder)},
        actor='operator',
    )
    return {
        'ok':True,
        'message':f"Folder open request sent for {item['name']}; Explorer state is not verified.",
        'receipt':receipt,
        'claim_state':'requested',
    }

def open_extension_inventory_url(d):
    item=_inventory_lookup(d.get('id') if isinstance(d,dict) else '')
    if not item:
        return {'ok':False,'message':'Inventory item not found. No URL was opened.'}
    url=str(item.get('url') or '').strip()
    if not url.lower().startswith(('http://127.0.0.1','http://localhost')):
        return {'ok':False,'message':'Only registered localhost URLs may be opened from Phase 1 inventory.'}
    openurl(url)
    receipt=make_tool_receipt(
        'browser.open_extension_inventory_url',
        'requested',
        details={'item_id':item['id'],'url':url},
        actor='operator',
    )
    return {
        'ok':True,
        'message':f"Browser open request sent for {item['name']}; tab state is not verified.",
        'receipt':receipt,
        'claim_state':'requested',
    }

def launch_extension_inventory_item(d):
    item=_inventory_lookup(d.get('id') if isinstance(d,dict) else '')
    if not item:
        return {'ok':False,'message':'Inventory item not found. No process was launched.'}
    item_id=str(item.get('id') or '')
    if item_id=='app:comfyui':
        if not COMFY_MAIN.is_file():
            return {'ok':False,'message':'ComfyUI main.py is missing. No process was launched.'}
        result=comfy_normal_call('spawn',source='webui',timeout=330)
        receipt=make_tool_receipt(
            'comfy.start','verified' if result.get('ok') else 'blocked',
            checks=[{'id':'normal_controller','ok':bool(result.get('ok')),'message':str(result.get('message') or '')}],
            details={'state':result.get('state'),'source':'extension_inventory'},
            actor='operator',
        )
        return {'ok':bool(result.get('ok')),'message':str(result.get('message') or 'ComfyUI normal controller returned no message.'),'state':result.get('state'),'controller':result,'receipt':receipt,'claim_state':'verified' if result.get('ok') else 'blocked'}

    allowed_names=EXTENSION_INVENTORY_SAFE_FLEET_LAUNCH.get(item_id)
    path=_inventory_resolve_path(item.get('path'))
    if not allowed_names or path is None or not path.is_file():
        return {'ok':False,'message':'This inventory item is not in the Phase 1 launch allowlist.'}
    if path.name.casefold() not in {name.casefold() for name in allowed_names}:
        return {'ok':False,'message':'Executable identity does not match the Phase 1 launch allowlist.'}
    if not _inventory_allowed_path(path):
        return {'ok':False,'message':'Executable path is outside the approved FOXAI / Hanger Bay roots.'}
    proc=subprocess.Popen([str(path)],cwd=str(path.parent))
    receipt=make_tool_receipt(
        'extension_inventory.launch',
        'requested',
        details={'item_id':item_id,'path':str(path),'pid':getattr(proc,'pid',None)},
        actor='operator',
    )
    return {
        'ok':True,
        'message':f"Launch requested for {item['name']}; application state is not yet verified.",
        'receipt':receipt,
        'claim_state':'requested',
    }
