# EXTENSION_MANAGER_SAFE_STATE_PHASE2_BACKEND_START
EXTENSION_STATE_MAX_BYTES=64*1024
EXTENSION_STATE_RESERVED_KEYS={'_meta','schema','updated'}
EXTENSION_STATE_ACTIONS={'enable','disable','restore'}
extension_state_lock=RLock()
_extension_inventory_snapshot_phase1=extension_inventory_snapshot
_launch_extension_inventory_item_phase1=launch_extension_inventory_item

def _extension_state_path():
    return ROOT/'Config'/'extension_state.json'

def _extension_state_read():
    path=_extension_state_path()
    if not path.exists():
        return {},{'exists':False,'sha256':None,'size_bytes':0,'error':None}
    if not path.is_file():
        raise ValueError('extension_state.json is not a regular file.')
    size=path.stat().st_size
    if size>EXTENSION_STATE_MAX_BYTES:
        raise ValueError('extension_state.json exceeds the 64 KB safety limit.')
    try:
        raw=json.loads(path.read_text(encoding='utf-8'))
    except Exception as exc:
        raise ValueError(f'extension_state.json is invalid JSON: {exc}') from exc
    if not isinstance(raw,dict):
        raise ValueError('extension_state.json root must be an object.')
    seen=set()
    for key,value in raw.items():
        if key in EXTENSION_STATE_RESERVED_KEYS:
            continue
        folded=str(key).casefold()
        if folded in seen:
            raise ValueError('extension_state.json contains case-insensitive duplicate keys.')
        seen.add(folded)
        if not isinstance(value,dict) or not isinstance(value.get('enabled'),bool):
            raise ValueError(f'Invalid extension override record: {key}')
    return raw,{
        'exists':True,
        'sha256':hashlib.sha256(path.read_bytes()).hexdigest(),
        'size_bytes':size,
        'error':None,
    }

def _extension_state_override(raw,key):
    value=raw.get(key) if isinstance(raw,dict) else None
    if not isinstance(value,dict) or 'enabled' not in value:
        return None
    return bool(value.get('enabled'))

def _extension_dependency_values(raw):
    result=[]
    for field in ('depends_on','dependencies','requires'):
        value=raw.get(field) if isinstance(raw,dict) else None
        if isinstance(value,dict):
            values=list(value.keys())
        elif isinstance(value,(list,tuple,set)):
            values=list(value)
        elif isinstance(value,str):
            values=[value]
        else:
            values=[]
        for item in values:
            if isinstance(item,dict):
                item=item.get('key') or item.get('id') or item.get('name')
            item=str(item or '').strip()
            if item and item.casefold() not in {x.casefold() for x in result}:
                result.append(item)
    return result

def _extension_state_catalog():
    raw_state,state_meta=_extension_state_read()
    records=[]
    for record in _inventory_manifest_records():
        path=record.get('manifest_path')
        if not isinstance(path,Path):
            continue
        try:
            rel=path.relative_to(ROOT)
        except Exception:
            continue
        top=rel.parts[0].casefold() if rel.parts else ''
        if top not in {'extensions','modules'}:
            continue
        raw=record.get('raw') if isinstance(record.get('raw'),dict) else {}
        key=str(record.get('key') or '').strip()
        if not key:
            continue
        kind=str(record.get('kind') or 'extension').strip().lower()
        required=bool(raw.get('required') or raw.get('reserved') or kind in {'core','system','department'})
        manifest_default=bool(raw.get('enabled',True))
        override=_extension_state_override(raw_state,key)
        effective=manifest_default if override is None else override
        records.append({
            'key':key,
            'key_fold':key.casefold(),
            'name':str(record.get('name') or key),
            'kind':kind,
            'required':required,
            'manifest_default':manifest_default,
            'override_present':override is not None,
            'override_enabled':override,
            'effective_enabled':effective,
            'dependencies':_extension_dependency_values(raw),
            'manifest_path':path,
            'manifest_sha256':hashlib.sha256(path.read_bytes()).hexdigest() if path.is_file() else None,
            'manifest_valid':not record.get('error') and not record.get('missing_fields'),
            'health_warning':bool(record.get('error') or record.get('missing_fields') or record.get('missing_tools')),
            'raw':raw,
        })
    by_key={}
    for item in records:
        if item['key_fold'] in by_key:
            raise ValueError(f"Duplicate extension key discovered: {item['key']}")
        by_key[item['key_fold']]=item
    for item in records:
        dependents=[]
        for other in records:
            if other is item:
                continue
            if item['key_fold'] in {str(dep).casefold() for dep in other['dependencies']}:
                dependents.append(other['key'])
        item['dependents']=sorted(dependents,key=str.casefold)
        item['eligible']=bool(not item['required'] and item['manifest_valid'])
        item['lock_reason']='' if item['eligible'] else ('Required/core/department extensions cannot be state-overridden.' if item['required'] else 'Manifest validation must pass before state can be changed.')
    return records,by_key,raw_state,state_meta

def _extension_state_find(target):
    target=str(target or '').strip()
    records,by_key,raw_state,state_meta=_extension_state_catalog()
    if not target:
        return None,records,by_key,raw_state,state_meta
    direct=by_key.get(target.casefold())
    if direct:
        return direct,records,by_key,raw_state,state_meta
    inventory=_extension_inventory_snapshot_phase1()
    match=next((item for item in inventory.get('items',[]) if str(item.get('id'))==target),None)
    if match:
        candidates=[
            str(match.get('id') or '').split(':',1)[-1],
            str(match.get('name') or ''),
        ]
        manifest_path=str(match.get('manifest_path') or '').casefold()
        for record in records:
            if manifest_path and str(record['manifest_path']).casefold()==manifest_path:
                return record,records,by_key,raw_state,state_meta
            if record['key_fold'] in {value.casefold() for value in candidates if value}:
                return record,records,by_key,raw_state,state_meta
    return None,records,by_key,raw_state,state_meta

def _extension_state_document_after(raw_state,item,action,proposal_time):
    result=json.loads(json.dumps(raw_state)) if raw_state else {}
    result={key:value for key,value in result.items() if key not in {'schema','updated'}}
    current=result.get(item['key']) if isinstance(result.get(item['key']),dict) else {}
    if action=='restore':
        result.pop(item['key'],None)
    else:
        current=dict(current)
        current['enabled']=action=='enable'
        current['modified']=proposal_time
        current['source']='operator_override'
        current['manifest_default']=item['manifest_default']
        result[item['key']]=current
    overrides=[key for key,value in result.items() if key not in EXTENSION_STATE_RESERVED_KEYS and isinstance(value,dict) and 'enabled' in value]
    if overrides:
        result['_meta']={
            'schema':1,
            'updated':proposal_time,
            'writer':'Extension Manager Phase 2',
            'override_count':len(overrides),
        }
        ordered={'_meta':result['_meta']}
        for key in sorted(overrides,key=str.casefold):
            ordered[key]=result[key]
        return ordered
    return {}

def _extension_state_json_text(document):
    if not document:
        return ''
    return json.dumps(document,indent=2,sort_keys=False)+'\n'

def _extension_state_diff(before,after):
    before_text=_extension_state_json_text(before) if before else '[FILE ABSENT]\n'
    after_text=_extension_state_json_text(after) if after else '[FILE ABSENT]\n'
    import difflib
    return ''.join(difflib.unified_diff(
        before_text.splitlines(keepends=True),
        after_text.splitlines(keepends=True),
        fromfile='Config/extension_state.json (before)',
        tofile='Config/extension_state.json (after)',
    )) or '(no change)'

def _extension_state_effective(item,document):
    override=_extension_state_override(document,item['key'])
    return item['manifest_default'] if override is None else override

def _extension_state_preview_contract(target,action,proposal_time=None):
    action=str(action or '').strip().lower()
    proposal_time=str(proposal_time or now()).strip()
    try:
        proposal_dt=datetime.fromisoformat(proposal_time)
    except Exception:
        return {'ok':False,'message':'Proposal time is invalid. Refresh the preview.'}
    if abs((datetime.now()-proposal_dt).total_seconds())>1800:
        return {'ok':False,'message':'State preview expired after 30 minutes. Refresh the preview.'}
    item,records,by_key,raw_state,state_meta=_extension_state_find(target)
    if action not in EXTENSION_STATE_ACTIONS:
        return {'ok':False,'message':'Action must be enable, disable, or restore.'}
    if not item:
        return {'ok':False,'message':'Optional manifest-backed extension not found.'}
    blockers=[]; warnings=[]
    if not item['eligible']:
        blockers.append(item['lock_reason'] or 'State control is locked.')
    if action=='restore' and not item['override_present']:
        blockers.append('No override exists; the extension already follows its manifest default.')
    proposed=_extension_state_document_after(raw_state,item,action,proposal_time)
    proposed_effective=_extension_state_effective(item,proposed)
    if proposed_effective==item['effective_enabled'] and not (action=='restore' and item['override_present']):
        blockers.append('The requested action would not change the effective state.')
    missing_dependencies=[]; disabled_dependencies=[]
    for dep in item['dependencies']:
        target_dep=by_key.get(str(dep).casefold())
        if not target_dep:
            missing_dependencies.append(dep)
        elif not target_dep['effective_enabled']:
            disabled_dependencies.append(target_dep['key'])
    enabled_dependents=[]
    for dependent_key in item['dependents']:
        dependent=by_key.get(str(dependent_key).casefold())
        if dependent and dependent['effective_enabled']:
            enabled_dependents.append(dependent['key'])
    if proposed_effective:
        if missing_dependencies:
            blockers.append('Missing declared dependencies: '+', '.join(missing_dependencies))
        if disabled_dependencies:
            blockers.append('Disabled declared dependencies: '+', '.join(disabled_dependencies))
    else:
        if enabled_dependents:
            blockers.append('Enabled dependents require this extension: '+', '.join(enabled_dependents))
    if item['health_warning']:
        warnings.append('The manifest or declared tool health needs attention. State changes do not install or repair software.')
    if action=='enable':
        warnings.append('Enabling changes only the FOXAI override; it does not install missing executables or packages.')
    if not proposed_effective:
        warnings.append('Disabling does not terminate an already running process. It blocks Extension Manager launch eligibility and records the state override for state-aware components.')
    state_effect='delete override file' if not proposed and state_meta['exists'] else ('no state file' if not proposed else ('create override file' if not state_meta['exists'] else 'update override file'))
    before_sha=state_meta.get('sha256')
    preview_core={
        'target':item['key'],
        'action':action,
        'proposal_time':proposal_time,
        'manifest_sha256':item['manifest_sha256'],
        'state_before_sha256':before_sha,
        'state_before_exists':state_meta['exists'],
        'proposed_document':proposed,
        'proposed_effective':proposed_effective,
        'blockers':blockers,
    }
    digest=hashlib.sha256(json.dumps(preview_core,sort_keys=True,separators=(',',':')).encode('utf-8')).hexdigest()
    phrase=f"APPROVE EXTENSION STATE {action.upper()} {item['key'].upper()}"
    return {
        'ok':True,
        'target':item['key'],
        'key':item['key'],
        'name':item['name'],
        'action':action,
        'proposal_time':proposal_time,
        'current_effective':item['effective_enabled'],
        'manifest_default':item['manifest_default'],
        'override_present':item['override_present'],
        'override_enabled':item['override_enabled'],
        'proposed_effective':proposed_effective,
        'dependencies':item['dependencies'],
        'dependents':item['dependents'],
        'enabled_dependents':enabled_dependents,
        'warnings':warnings,
        'blockers':blockers,
        'can_apply':not blockers,
        'state_file':str(_extension_state_path()),
        'state_file_exists':state_meta['exists'],
        'state_file_effect':state_effect,
        'diff':_extension_state_diff(raw_state,proposed),
        'preview_digest':digest,
        'approval_phrase':phrase,
        'preview_core':preview_core,
        'configuration_modified':False,
        'read_only':True,
        'message':'Exact state preview ready.' if not blockers else 'Preview created, but the state change is blocked.',
    }

def extension_state_change_preview(d):
    d=d if isinstance(d,dict) else {}
    try:
        result=_extension_state_preview_contract(d.get('target') or d.get('id') or d.get('key'),d.get('action'))
    except Exception as exc:
        return {'ok':False,'message':f'State preview failed closed: {type(exc).__name__}: {exc}','state':'blocked_invalid_state','configuration_modified':False}
    if result.get('ok'):
        result.pop('preview_core',None)
    return result

def _extension_state_write_atomic(path,document):
    path.parent.mkdir(parents=True,exist_ok=True)
    stage=path.with_name(f'.{path.name}.phase2.{os.getpid()}.new')
    try:
        data=_extension_state_json_text(document).encode('utf-8')
        if not data:
            raise ValueError('Atomic writer requires a non-empty state document.')
        if len(data)>EXTENSION_STATE_MAX_BYTES:
            raise ValueError('Proposed extension state exceeds the 64 KB safety limit.')
        with stage.open('wb') as handle:
            handle.write(data); handle.flush(); os.fsync(handle.fileno())
        json.loads(stage.read_text(encoding='utf-8'))
        os.replace(stage,path)
    finally:
        try: stage.unlink(missing_ok=True)
        except Exception: pass

def _extension_state_restore_original(path,before_exists,before_bytes,quarantine=None):
    if quarantine and quarantine.exists():
        if path.exists(): path.unlink()
        os.replace(quarantine,path)
        return
    if before_exists:
        stage=path.with_name(f'.{path.name}.rollback.{os.getpid()}')
        try:
            with stage.open('wb') as handle:
                handle.write(before_bytes); handle.flush(); os.fsync(handle.fileno())
            os.replace(stage,path)
        finally:
            try: stage.unlink(missing_ok=True)
            except Exception: pass
    else:
        path.unlink(missing_ok=True)

def apply_extension_state_change(d):
    d=d if isinstance(d,dict) else {}
    target=d.get('target') or d.get('id') or d.get('key')
    action=str(d.get('action') or '').strip().lower()
    supplied_digest=str(d.get('preview_digest') or '').strip()
    supplied_phrase=str(d.get('approval_phrase') or '').strip()
    with extension_state_lock:
        try:
            preview=_extension_state_preview_contract(target,action,d.get('proposal_time'))
        except Exception as exc:
            return {'ok':False,'message':f'State apply stopped fail-closed before any write: {type(exc).__name__}: {exc}','state':'stopped_fail_closed','verified':True,'configuration_modified':False}
        if not preview.get('ok'):
            return preview
        if not preview.get('can_apply'):
            return {'ok':False,'message':'State change is blocked: '+'; '.join(preview.get('blockers') or [])}
        if supplied_digest!=preview.get('preview_digest'):
            return {'ok':False,'message':'Preview digest mismatch. Refresh the preview; no state was changed.'}
        if supplied_phrase!=preview.get('approval_phrase'):
            return {'ok':False,'message':'Exact approval phrase did not match. No state was changed.'}
        path=_extension_state_path()
        before_exists=path.is_file()
        before_bytes=path.read_bytes() if before_exists else b''
        before_sha=hashlib.sha256(before_bytes).hexdigest() if before_exists else None
        proposed=preview['preview_core']['proposed_document']
        stamp=datetime.now().strftime('%Y%m%dT%H%M%S_%f')
        safe_key=slug(preview['key']).lower() or 'extension'
        backup_root=ROOT/'Backups'/'ExtensionState'/f'{stamp}_{safe_key}_{action}'
        reports_root=ROOT/'Reports'/'ExtensionState'
        backup_path=backup_root/'extension_state.json'
        absent_marker=backup_root/'ABSENT_BEFORE.json'
        try:
            backup_root.mkdir(parents=True,exist_ok=False)
            if before_exists:
                backup_path.write_bytes(before_bytes)
                if hashlib.sha256(backup_path.read_bytes()).hexdigest()!=before_sha:
                    raise ValueError('Backup verification failed.')
            else:
                absent_marker.write_text(json.dumps({'state':'absent_before','verified':True},indent=2),encoding='utf-8')
        except Exception as exc:
            return {'ok':False,'message':f'Backup preparation failed. No state was changed: {exc}','state':'stopped_fail_closed','verified':True,'configuration_modified':False}
        quarantine=None
        rollback_performed=False
        try:
            if proposed:
                _extension_state_write_atomic(path,proposed)
            else:
                if path.exists():
                    quarantine=path.with_name(f'.{path.name}.restore.{os.getpid()}.quarantine')
                    os.replace(path,quarantine)
            after_exists=path.is_file()
            after_document,after_meta=_extension_state_read()
            if after_document!=proposed or after_exists!=bool(proposed):
                raise ValueError('State-file read-back verification failed.')
            item,_,_,current_state,_=_extension_state_find(preview['key'])
            if not item or item['effective_enabled']!=preview['proposed_effective']:
                raise ValueError('Effective extension state verification failed.')
            reports_root.mkdir(parents=True,exist_ok=True)
            receipt_path=reports_root/f'Extension_State_{stamp}_{safe_key}_{action}.json'
            receipt={
                'action':'extension_state_change',
                'created':now(),
                'state':'applied_verified',
                'verified':True,
                'operator_approved':True,
                'extension_key':preview['key'],
                'extension_name':preview['name'],
                'requested_action':action,
                'approval_phrase':preview['approval_phrase'],
                'preview_digest':preview['preview_digest'],
                'manifest_default':preview['manifest_default'],
                'before_effective':preview['current_effective'],
                'after_effective':preview['proposed_effective'],
                'before_override':preview['override_enabled'] if preview['override_present'] else None,
                'after_override':_extension_state_override(current_state,preview['key']),
                'state_file':str(path),
                'state_file_before_exists':before_exists,
                'state_file_after_exists':after_exists,
                'state_file_before_sha256':before_sha,
                'state_file_after_sha256':after_meta.get('sha256'),
                'state_file_effect':preview['state_file_effect'],
                'dependencies':preview['dependencies'],
                'enabled_dependents':preview['enabled_dependents'],
                'backup_path':str(backup_path if before_exists else absent_marker),
                'rollback_performed':False,
                'install_performed':False,
                'remove_performed':False,
                'update_performed':False,
                'download_performed':False,
            }
            receipt_stage=receipt_path.with_name(f'.{receipt_path.name}.{os.getpid()}.new')
            try:
                receipt_stage.write_text(json.dumps(receipt,indent=2),encoding='utf-8')
                os.replace(receipt_stage,receipt_path)
            finally:
                try: receipt_stage.unlink(missing_ok=True)
                except Exception: pass
            verified_receipt=json.loads(receipt_path.read_text(encoding='utf-8'))
            if verified_receipt.get('state')!='applied_verified' or verified_receipt.get('verified') is not True:
                raise ValueError('Receipt verification failed.')
            if quarantine and quarantine.exists():
                quarantine.unlink()
            return {
                'ok':True,
                'message':f"VERIFIED: {preview['name']} now follows the {('enabled' if preview['proposed_effective'] else 'disabled')} effective state.",
                'state':'applied_verified',
                'verified':True,
                'key':preview['key'],
                'enabled':preview['proposed_effective'],
                'state_file':str(path),
                'state_file_exists':path.is_file(),
                'backup_path':str(backup_path if before_exists else absent_marker),
                'receipt_path':str(receipt_path),
                'rollback_performed':False,
            }
        except Exception as exc:
            rollback_performed=True
            try:
                _extension_state_restore_original(path,before_exists,before_bytes,quarantine)
                restored_exists=path.is_file()
                restored_bytes=path.read_bytes() if restored_exists else b''
                restored_ok=(restored_exists==before_exists and restored_bytes==before_bytes)
            except Exception as rollback_exc:
                return {
                    'ok':False,
                    'message':f'Extension state apply failed and rollback also failed: {exc}; rollback: {rollback_exc}',
                    'state':'rollback_failed',
                    'verified':False,
                    'rollback_performed':True,
                }
            return {
                'ok':False,
                'message':f'Extension state apply failed and was rolled back: {exc}',
                'state':'rolled_back_verified' if restored_ok else 'rollback_failed',
                'verified':bool(restored_ok),
                'rollback_performed':True,
            }

def _extension_state_control_map():
    records,_,_,meta=_extension_state_catalog()
    return {item['key_fold']:{
        'key':item['key'],
        'eligible':item['eligible'],
        'lock_reason':item['lock_reason'],
        'manifest_default':item['manifest_default'],
        'override_present':item['override_present'],
        'override_enabled':item['override_enabled'],
        'effective_enabled':item['effective_enabled'],
        'dependencies':item['dependencies'],
        'dependents':item['dependents'],
        'state_file_exists':meta['exists'],
        'manifest_path':str(item['manifest_path']),
    } for item in records}

def extension_inventory_snapshot():
    data=_extension_inventory_snapshot_phase1()
    try:
        controls=_extension_state_control_map()
        state_raw,state_meta=_extension_state_read()
        override_count=sum(1 for key,value in state_raw.items() if key not in EXTENSION_STATE_RESERVED_KEYS and isinstance(value,dict) and 'enabled' in value)
        for item in data.get('items',[]):
            candidates=[
                str(item.get('id') or '').split(':',1)[-1].casefold(),
                str(item.get('name') or '').casefold(),
            ]
            manifest_path=str(item.get('manifest_path') or '').casefold()
            control=None
            for key,value in controls.items():
                if key in candidates:
                    control=value; break
                record_path=str(value.get('manifest_path') or '').casefold()
                if manifest_path and record_path==manifest_path:
                    control=value; break
            if control:
                item['state_control']=control
        data['read_only']=True
        data['report_only']=True
        data['guarded_state_write_available']=True
        data['configuration_modified']=False
        data['state_file_created']=False
        data['summary']['state_controls']=sum(1 for value in controls.values() if value['eligible'])
        data['summary']['state_overrides']=override_count
        data['summary']['state_enabled']=sum(1 for value in controls.values() if value['effective_enabled'])
        data['summary']['state_disabled']=sum(1 for value in controls.values() if not value['effective_enabled'])
        data['sources']['extension_state']={
            'path':str(_extension_state_path()),
            'exists':state_meta['exists'],
            'overrides':override_count,
            'mode':'guarded explicit overrides' if state_meta['exists'] else 'manifest defaults; no state file created',
        }
        data['safety'].update({
            'configuration_write':'optional extension state only; exact preview + typed approval + digest + backup + receipt + rollback',
            'required_state_change':False,
            'install':False,
            'remove':False,
            'update':False,
            'download':False,
        })
        data['message']=f"Inventory: {data['summary']['total']} component(s), {data['summary']['state_controls']} guarded state control(s), {override_count} override(s)."
    except Exception as exc:
        data['state_control_error']=f'{type(exc).__name__}: {exc}'
        data['summary']['state_controls']=0
        data['summary']['state_overrides']=0
        data['sources']['extension_state']={
            'path':str(_extension_state_path()),
            'exists':_extension_state_path().is_file(),
            'mode':'fail-closed: state controls unavailable',
            'error':str(exc),
        }
    return data

def launch_extension_inventory_item(d):
    item=_inventory_lookup(d.get('id') if isinstance(d,dict) else '')
    control=(item or {}).get('state_control') or {}
    if control and not control.get('effective_enabled'):
        return {
            'ok':False,
            'message':f"{item.get('name') or 'Extension'} is disabled by an approved extension-state override. Restore or enable it through the guarded preview before launch.",
            'state':'blocked_extension_disabled',
            'configuration_modified':False,
        }
    return _launch_extension_inventory_item_phase1(d)
