def suggest_manifest_repair(d):
    manifest=d.get('manifest') or ''
    key=d.get('key') or ''
    target=None
    if manifest and manifest!='built-in':
        p=Path(manifest)
        if p.exists():
            target=p
    if target is None and key:
        for p in manifest_candidates():
            item=normalize_extension_manifest(p)
            if item.get('key')==key:
                target=p
                break
    if target is None:
        return {'ok':False,'message':'Could not find a manifest file for repair suggestion.'}

    raw=jread(target,{})
    folder_name=target.parent.name
    suggested=dict(raw)
    if not suggested.get('id'):
        suggested['id']=slug(folder_name).lower()
    if not suggested.get('name'):
        suggested['name']=folder_name.replace('_',' ').replace('-',' ').title()
    if not suggested.get('version'):
        suggested['version']='0.1.0'
    if not suggested.get('type') and not suggested.get('kind'):
        suggested['type']='department' if 'Departments' in str(target) else 'extension'
    if not suggested.get('description'):
        suggested['description']=f"{suggested.get('name','Module')} module for Kayock Command OS."
    if 'enabled' not in suggested:
        suggested['enabled']=True
    repaired=json.dumps(suggested,indent=2,ensure_ascii=False)
    return {
        'ok':True,
        'message':'Manifest repair suggestion generated.',
        'manifest':str(target),
        'folder':str(target.parent),
        'original':json.dumps(raw,indent=2,ensure_ascii=False),
        'suggested':repaired
    }


def apply_manifest_repair(d):
    manifest=d.get('manifest') or ''
    suggested_text=d.get('suggested') or ''
    key=d.get('key') or ''
    target=None

    if manifest and manifest!='built-in':
        p=Path(manifest)
        if p.exists():
            target=p

    if target is None and key:
        for p in manifest_candidates():
            item=normalize_extension_manifest(p)
            if item.get('key')==key:
                target=p
                break

    if target is None:
        return {'ok':False,'message':'Could not find manifest file to repair.'}

    if not suggested_text.strip():
        suggestion=suggest_manifest_repair({'manifest':str(target),'key':key})
        if not suggestion.get('ok'):
            return suggestion
        suggested_text=suggestion.get('suggested','')

    try:
        suggested_json=json.loads(suggested_text)
    except Exception as e:
        return {'ok':False,'message':f'Suggested manifest is not valid JSON: {e}'}

    before=normalize_extension_manifest(target)
    backup_dir=FOLDERS.get('manifest_backups',ROOT/'Backups'/'Manifests')
    backup_dir.mkdir(parents=True,exist_ok=True)
    stamp=datetime.now().strftime('%Y%m%d_%H%M%S')
    backup_path=backup_dir/f"{slug(target.parent.name)}_manifest_{stamp}.json"

    try:
        shutil.copy2(target,backup_path)
    except Exception as e:
        return {'ok':False,'message':f'Could not back up manifest before repair: {e}'}

    try:
        jwrite(target,suggested_json)
    except Exception as e:
        try:
            shutil.copy2(backup_path,target)
        except Exception:
            pass
        return {'ok':False,'message':f'Could not write repaired manifest. Original was restored if possible. Error: {e}','backup':str(backup_path)}

    after=normalize_extension_manifest(target)
    validation=validate_extensions()
    if active_project:
        timeline(active_project,f'Applied safe manifest repair: {target.name} backed up to {backup_path.name}')

    return {
        'ok':True,
        'message':'Manifest repair applied safely.',
        'manifest':str(target),
        'backup':str(backup_path),
        'before':{
            'status':before.get('status'),
            'missing':before.get('missing',[]),
            'version':before.get('version')
        },
        'after':{
            'status':after.get('status'),
            'missing':after.get('missing',[]),
            'version':after.get('version')
        },
        'validation':validation
    }



def repair_bay_prepare_handoff(d=None):
    request=d or {}
    finding_id=str(request.get('finding_id') or '').strip()
    level=str(request.get('level') or 'guided').strip().lower()
    mode=str(request.get('mode') or 'full').strip().lower()
    full_only={'full_python_syntax','configuration_json','zero_byte_live_files','log_growth','root_launcher_inventory'}
    if finding_id in full_only:
        mode='full'
    if mode not in {'quick','full'}:
        mode='full'
    try:
        from core.repair_bay_diagnostics import run_repair_bay_scan
        from core.repair_bay_handoff import build_repair_handoff
        report=run_repair_bay_scan(
            ROOT,
            mode=mode,
            context={
                'interface':'WebUI',
                'active_project':active_project or '',
                'operator':'local',
                'purpose':'guarded_repair_handoff',
            },
        )
        scan_safety=report.get('safety') or {}
        if not report.get('read_only') or bool(scan_safety.get('network_used')) or bool(scan_safety.get('commands_run')) or int(scan_safety.get('files_written') or 0)!=0 or int(scan_safety.get('repairs_applied') or 0)!=0:
            return {'ok':False,'message':'Guarded handoff blocked because the grounding scan did not verify read-only safety.','read_only':True,'changes_applied':0,'mission_staged':False}
        packet=build_repair_handoff(ROOT,report,finding_id,level=level)
        safety=packet.get('safety_limits') or {}
        checks=[
            {'id':'read_only','ok':bool(packet.get('read_only')),'message':'Handoff preparation was read-only.'},
            {'id':'no_changes','ok':int(packet.get('changes_applied') or 0)==0,'message':'No repair or project change was applied.'},
            {'id':'mission_not_staged','ok':not bool(packet.get('mission_staged')),'message':'Mission Console review is required before staging.'},
            {'id':'implementation_not_authorized','ok':not bool(packet.get('implementation_authorized')),'message':'The handoff does not authorize implementation.'},
            {'id':'no_network','ok':not bool(safety.get('network_allowed')),'message':'The proposed planning mission forbids network use.'},
            {'id':'no_auto_apply','ok':not bool(safety.get('automatic_apply_allowed')),'message':'Automatic application is forbidden.'},
        ]
        verified=bool(packet.get('ok')) and all(item['ok'] for item in checks)
        packet['receipt']=make_tool_receipt(
            'repair_bay.guarded_handoff',
            'verified' if verified else 'blocked',
            checks=checks,
            details={
                'finding_id':(packet.get('finding') or {}).get('id'),
                'eligible':bool(packet.get('eligible')),
                'repair_kind':packet.get('repair_kind'),
                'affected_paths':len(packet.get('affected_paths') or []),
                'implementation_authorized':False,
            },
            actor='operator',
        )
        packet['claim_state']='verified' if verified else 'blocked'
        return packet
    except Exception as exc:
        return {
            'ok':False,
            'message':f'Guarded repair handoff failed closed: {type(exc).__name__}: {exc}',
            'read_only':True,
            'changes_applied':0,
            'mission_staged':False,
            'implementation_authorized':False,
        }


