            lines.append(f"- `{r.get('key')}` — {r.get('kind')} — exists={r.get('exists')} — `{r.get('path')}`")
        mp.write_text('\n'.join(lines),encoding='utf-8')
        report['exported']={'json':str(jp),'markdown':str(mp),'folder':str(out)}

    return report


