def web_model_profile_runtime(model_path,profile_id='',model_record=None):
    profile_key=str(profile_id or '').strip()
    source_type=str((model_record or {}).get('source') or '')
    source_label=str((model_record or {}).get('source_label') or source_type or 'LOCAL')
    if not profile_key:
        return {
            'ok':True,
            'profile_id':'',
            'label':'Exact GGUF',
            'reasoning_mode':'current',
            'reasoning_budget':None,
            'vision':False,
            'projector_path':None,
            'projector_sha256':None,
            'require_verified_settings':False,
            'model_source':source_type,
            'model_source_label':source_label,
        }
    profile=WEB_MODEL_PROFILE_RUNTIME.get(profile_key)
    if not profile:
        return {'ok':False,'message':'Unknown model profile. No engine action occurred.'}
    selected_name=Path(model_path).name.casefold()
    expected_name=str(profile['model_filename']).casefold()
    if selected_name != expected_name:
        return {
            'ok':False,
            'message':'Selected model does not match the requested profile. No engine action occurred.',
        }
    expected_source=str(profile.get('source') or '')
    if expected_source and source_type != expected_source:
        return {
            'ok':False,
            'message':f'Selected model source does not match the requested {expected_source} profile. No fallback occurred.',
        }
    projector=None
    if profile.get('vision'):
        projector=verified_vision_projector()
        if not projector.get('ok'):
            return projector
    return {
        'ok':True,
        'profile_id':profile_key,
        'label':profile['label'],
        'reasoning_mode':profile['reasoning_mode'],
        'reasoning_budget':profile['reasoning_budget'],
        'vision':bool(profile.get('vision')),
        'projector_path':projector.get('path') if projector else None,
        'projector_sha256':projector.get('sha256') if projector else None,
        'require_verified_settings':True,
        'model_source':source_type,
        'model_source_label':source_label,
    }

def start_chat(model_path,profile_id=''):
    global chat_model,chat_process,chat_profile_id,chat_model_source
    try:
        model_record=model_source_registry.record_for_path(model_path)
    except ModelSourceError as exc:
        return {'ok':False,'message':f'Model-source registry error: {exc}. No engine action occurred.'}
    if not model_record:
        return {'ok':False,'message':'Selected model is not inside an approved USB or host-PC model source. No engine action occurred.'}
    m=Path(model_record['path'])
    if not m.is_file():
        return {'ok':False,'message':'Selected approved model is unavailable. No fallback or engine action occurred.'}
    profile=web_model_profile_runtime(m,profile_id,model_record)
    if not profile.get('ok'): return profile
    if not profile.get('vision'):
        clear_active_mission_image()
        messages[:]=compact_prior_images(messages)
    settings=chat_server_settings()
    runtime_settings=dict(settings)
    runtime_settings.update({
        'profile_id':profile['profile_id'],
        'profile_label':profile['label'],
        'reasoning_mode':profile['reasoning_mode'],
        'reasoning_budget':profile['reasoning_budget'],
        'vision':profile['vision'],
        'projector_path':profile['projector_path'],
        'projector_sha256':profile['projector_sha256'],
        'settings_verified':profile['require_verified_settings'],
        'model_source':model_record['source'],
        'model_source_label':model_record['source_label'],
        'model_source_id':model_record['source_id'],
        'model_path':model_record['path'],
        'model_source_machine':model_record.get('machine_name'),
        'model_source_remembered':model_record.get('remembered'),
        'model_source_session_only':model_record.get('session_only'),
        'silent_fallback_used':False,
    })
    result=web_llama_server.ensure_running(
        m,
        host=settings['host'],
        port=settings['port'],
        context=settings['context'],
        threads=settings['threads'],
        projector=profile['projector_path'],
        reasoning_mode=profile['reasoning_mode'],
        reasoning_budget=profile['reasoning_budget'],
        require_verified_settings=profile['require_verified_settings'],
    )
    chat_process=web_llama_server.process
    if not result.ok:
        return _shared_chat_failure(result)

    ready=web_llama_server.wait_until_ready(timeout=90)
    chat_process=web_llama_server.process
    if not ready.ok:
        return _shared_chat_failure(ready)

    chat_model=str(m)
    chat_profile_id=profile['profile_id']
    chat_model_source={
        key:model_record.get(key)
        for key in (
            'source','source_label','source_id','machine_name','remembered',
            'session_only','path','name','size_bytes'
        )
    }
    session_receipt=begin_web_mission_session()
    return _verified_shared_chat_response(m,result,ready,runtime_settings,session_receipt)

def stop_chat():
    global chat_process,chat_profile_id,chat_model_source
    clear_active_mission_image()
    messages[:]=compact_prior_images(messages)
    result=web_llama_server.stop()
