                out['kind'] = 'folder' if p.is_dir() else 'file'
                out['size'] = p.stat().st_size if p.is_file() else None
                out['modified'] = datetime.fromtimestamp(p.stat().st_mtime).isoformat(timespec='seconds')
        except Exception as e:
            out['error'] = str(e)
        return out
    def read_json(p):
