        actual_hash = sha(md) if md else ''
        expected_wc = int(meta.get('word_count') or ev.get('word_count') or 0)
        actual_wc = wc(body)
        prev_hash = str(meta.get('previous_draft_hash') or '')
        created_by = str(meta.get('created_by') or '')
