        while s < len(md) and md[s] in '\r\n ':
            s += 1
        j = md.find('\n## ', s)
        return (md[s:] if j < 0 else md[s:j]).strip()
    def wc(v):
        return len([x for x in re.split(r'\s+', (v or '').strip()) if x])
    def info(p):
